import { spawn } from "node:child_process";
import { mkdirSync, mkdtempSync, readdirSync, readFileSync, rmSync, writeFileSync, } from "node:fs";
import { createRequire } from "node:module";
import { tmpdir } from "node:os";
import { join } from "node:path";
import { fileURLToPath } from "node:url";
import { afterAll, beforeAll, describe, expect, it } from "vitest";
// runReplayProgress spawns a child, so it can't be unit-tested in-process. These
// tests spawn the real command wrapping a fake replay, and assert: stdout carries
// one line per trace (header, a per-trace pass/fail line with its duration, then a
// summary), the replay's stdout JSON is appended as a final JSONL event, the
// lines are teed to the --log file, the no-event close guard fires, and the
// child's exit code propagates.
const SOURCE_PATH = fileURLToPath(new URL("./replayProgress.ts", import.meta.url));
const require = createRequire(import.meta.url);
const TSX_LOADER = require.resolve("tsx");
describe("runReplayProgress (per-trace emitter)", () => {
    let tmpDir;
    let entryPath;
    beforeAll(() => {
        tmpDir = mkdtempSync(join(tmpdir(), "replay-progress-"));
        entryPath = join(tmpDir, "entry.mjs");
        writeFileSync(entryPath, `import { runReplayProgress } from ${JSON.stringify(SOURCE_PATH)}\n` +
            `runReplayProgress().catch((err) => { console.error(err); process.exit(1) })\n`);
    });
    afterAll(() => {
        rmSync(tmpDir, { recursive: true, force: true });
    });
    // Fake replay: emits per-trace progress to stderr (erroring on trace 3, each
    // trace carrying a duration), prints the ReplayResult JSON to stdout, exits
    // with `exitCode`.
    function writeFakeChild(count, exitCode) {
        const childPath = join(tmpDir, `child-${count}-${exitCode}.mjs`);
        writeFileSync(childPath, [
            `const total = ${count}`,
            `for (let i = 1; i <= total; i++) {`,
            `  const isErr = i === 3`,
            `  const errored = i >= 3 ? 1 : 0`,
            `  const item = { traceId: "trace" + i + "abcdef", error: isErr ? "missing OPENAI_API_KEY" : null, durationMs: 1000 }`,
            `  const p = { completed: i, total, succeeded: i - errored, errored, item }`,
            `  process.stderr.write("@@bitfab:progress " + JSON.stringify(p) + "\\n")`,
            `}`,
            `process.stdout.write(JSON.stringify({ testRunId: "abc", items: [{ traceId: "t1" }] }, null, 2) + "\\n")`,
            `process.exit(${exitCode})`,
        ].join("\n"));
        return childPath;
    }
    // Fake replay that emits NO progress at all (the old-SDK / unwired-onProgress
    // case): just prints the ReplayResult JSON and exits with `exitCode`.
    function writeNoProgressChild(exitCode) {
        const childPath = join(tmpDir, `noprog-${exitCode}.mjs`);
        writeFileSync(childPath, [
            `process.stdout.write(JSON.stringify({ testRunId: "np", items: [] }) + "\\n")`,
            `process.exit(${exitCode})`,
        ].join("\n"));
        return childPath;
    }
    // Fake modern-SDK replay: streams per-trace progress AND a terminal `complete`
    // event (carrying the enriched ReplayResult) over the stderr sentinel channel,
    // while a dependency floods STDOUT with non-JSON noise (as BAML / llmTracking
    // do). The stdout whole-buffer parse would fail, so this exercises the wrapper
    // building the final result from the sentinel instead.
    function writeStreamedCompleteChild() {
        const childPath = join(tmpDir, "streamed-complete.mjs");
        writeFileSync(childPath, [
            // Modern lineage run: items carry sourceTraceId (the persist key); the
            // server resolves via lineage and returns no id map, so traceId stays null.
            `const items = [`,
            `  { traceId: null, sourceTraceId: "src-1", error: null, durationMs: 10 },`,
            `  { traceId: null, sourceTraceId: "src-2", error: null, durationMs: 20 },`,
            `]`,
            `const total = items.length`,
            `for (let i = 1; i <= total; i++) {`,
            `  const p = { completed: i, total, succeeded: i, errored: 0, testRunId: "run-c", item: items[i - 1] }`,
            `  process.stderr.write("@@bitfab:progress " + JSON.stringify(p) + "\\n")`,
            `}`,
            `// Dependency noise on stdout: the whole-buffer JSON.parse would throw.`,
            `process.stdout.write("[BAML INFO] calling gpt-4o-mini\\n")`,
            `process.stdout.write("[llmTracking] tokens=123\\n")`,
            `// Terminal complete event on stderr carries the enriched ReplayResult.`,
            `const result = { testRunId: "run-c", items, testRunUrl: "http://x/run-c" }`,
            `const done = { type: "complete", completed: total, total, succeeded: total, errored: 0, testRunId: "run-c", result }`,
            `process.stderr.write("@@bitfab:progress " + JSON.stringify(done) + "\\n")`,
            `process.exit(0)`,
        ].join("\n"));
        return childPath;
    }
    let runSeq = 0;
    function run(args, extraEnv = {}, cwd = tmpDir) {
        // Pin --log and --events-log into the tmp dir so a run never writes the
        // default .bitfab files into the repo. Only inject when a real `--` command
        // follows, else the usage path would treat the flag as the command.
        const seq = runSeq++;
        const logPath = join(tmpDir, `progress-${seq}.log`);
        const eventsLogPath = join(tmpDir, `events-${seq}.jsonl`);
        let fullArgs = args;
        if (args.includes("--") && !args.includes("--run-dir")) {
            if (!args.includes("--log")) {
                fullArgs = ["--log", logPath, ...fullArgs];
            }
            if (!args.includes("--events-log")) {
                fullArgs = ["--events-log", eventsLogPath, ...fullArgs];
            }
        }
        const child = spawn(process.execPath, [entryPath, ...fullArgs], {
            stdio: ["ignore", "pipe", "pipe"],
            cwd,
            env: {
                ...process.env,
                NODE_OPTIONS: `--import ${TSX_LOADER}`,
                ...extraEnv,
            },
        });
        let stdout = "";
        child.stdout.on("data", (d) => {
            stdout += d;
        });
        let stderr = "";
        child.stderr.on("data", (d) => {
            stderr += d;
        });
        return new Promise((resolve, reject) => {
            child.on("error", reject);
            child.on("close", (code) => resolve({
                exitCode: code ?? -1,
                stdout,
                stderr,
                logPath,
                eventsLogPath,
            }));
        });
    }
    it("emits one relayable line per trace on stdout and writes progress plus completion events", async () => {
        const childPath = writeFakeChild(20, 0);
        const outPath = join(tmpDir, "result.json");
        const { stdout, exitCode, logPath, eventsLogPath } = await run([
            "--label",
            "generate-email",
            "--total",
            "20",
            "--out",
            outPath,
            "--",
            process.execPath,
            childPath,
        ]);
        expect(exitCode).toBe(0);
        // Header, one line per trace (with its duration), error reason inline, summary.
        expect(stdout).toContain("▶ generate-email · 20 traces");
        expect(stdout).toContain("✓ 1/20 · 1.0s");
        expect(stdout).toContain("✗ 3/20 · 1.0s · missing OPENAI_API_KEY");
        expect(stdout).toMatch(/⚠ done · 19 ok · 1 failed · [\d.]+s · avg 1\.0s/);
        // One line per trace: header + 20 traces + summary == 22 lines, no raw sentinel.
        expect(stdout).not.toContain("@@bitfab:progress");
        expect(stdout.trim().split("\n").length).toBe(22);
        // The full ReplayResult JSON is still written to --out when requested.
        const result = JSON.parse(readFileSync(outPath, "utf8"));
        expect(result.testRunId).toBe("abc");
        // Every printed line is teed to --log for `tail -f`: same lines as stdout.
        expect(readFileSync(logPath, "utf8")).toBe(stdout);
        const events = readFileSync(eventsLogPath, "utf8")
            .trim()
            .split("\n")
            .map((line) => JSON.parse(line));
        expect(events).toHaveLength(21);
        expect(events[0]).toEqual({
            type: "progress",
            completed: 1,
            total: 20,
            succeeded: 1,
            errored: 0,
            item: {
                originalTraceId: "trace1abcdef",
                replayTraceId: null,
                error: null,
                durationMs: 1000,
            },
        });
        expect(events[20]).toMatchObject({
            type: "complete",
            result: { testRunId: "abc", itemCount: 1 },
            items: [
                {
                    traceId: "t1",
                    replayTraceId: null,
                    originalTraceId: null,
                    error: null,
                    durationMs: null,
                },
            ],
        });
        expect(JSON.parse(readFileSync(events[20].items[0].itemPath, "utf8"))).toEqual({
            testRunId: "abc",
            originalTraceId: null,
            sourceTraceId: null,
            traceId: "t1",
            replayTraceId: null,
            error: null,
            durationMs: null,
        });
    });
    it("preserves enriched item fields for live evaluation when provided", async () => {
        const childPath = join(tmpDir, "enriched-child.mjs");
        writeFileSync(childPath, [
            `const p = { completed: 1, total: 1, succeeded: 1, errored: 0, testRunId: "run-1", item: { traceId: "source-1", replayTraceId: "local-replay-1", error: null, durationMs: 5, input: ["hi"], result: { ok: true }, originalOutput: { ok: false } } }`,
            `process.stderr.write("@@bitfab:progress " + JSON.stringify(p) + "\\n")`,
            `process.stdout.write(JSON.stringify({ testRunId: "enriched", items: [] }) + "\\n")`,
            `process.exit(0)`,
        ].join("\n"));
        const { eventsLogPath, exitCode } = await run([
            "--",
            process.execPath,
            childPath,
        ]);
        expect(exitCode).toBe(0);
        const [event] = readFileSync(eventsLogPath, "utf8")
            .trim()
            .split("\n")
            .map((line) => JSON.parse(line));
        expect(event.type).toBe("progress");
        expect(event.testRunId).toBe("run-1");
        expect(event.item).toEqual({
            originalTraceId: "source-1",
            replayTraceId: "local-replay-1",
            error: null,
            durationMs: 5,
            // The item file is keyed by the original (lineage) trace id, so live and
            // complete writes land on the same file even if an SDK also emits a
            // stray local replay id (captured on replayTraceId for reference).
            itemPath: expect.stringContaining("source-1.json"),
        });
        expect(JSON.parse(readFileSync(event.item.itemPath, "utf8"))).toEqual({
            testRunId: "run-1",
            originalTraceId: "source-1",
            sourceTraceId: "source-1",
            traceId: null,
            replayTraceId: "local-replay-1",
            input: ["hi"],
            result: { ok: true },
            originalOutput: { ok: false },
            error: null,
            durationMs: 5,
        });
    });
    it("remaps the current SDK wire shape (item.traceId = replay, item.sourceTraceId = source)", async () => {
        const childPath = join(tmpDir, "new-shape-child.mjs");
        writeFileSync(childPath, [
            `const p = { completed: 1, total: 1, succeeded: 1, errored: 0, testRunId: "run-1", item: { traceId: "local-replay-1", sourceTraceId: "source-1", sourceSpanId: "span-1", error: null, durationMs: 5, input: ["hi"], result: { ok: true }, originalOutput: { ok: false } } }`,
            `process.stderr.write("@@bitfab:progress " + JSON.stringify(p) + "\\n")`,
            `process.stdout.write(JSON.stringify({ testRunId: "enriched", items: [] }) + "\\n")`,
            `process.exit(0)`,
        ].join("\n"));
        const { eventsLogPath, exitCode } = await run([
            "--",
            process.execPath,
            childPath,
        ]);
        expect(exitCode).toBe(0);
        const [event] = readFileSync(eventsLogPath, "utf8")
            .trim()
            .split("\n")
            .map((line) => JSON.parse(line));
        expect(event.type).toBe("progress");
        // The plugin's item.originalTraceId stays the ORIGINAL trace; the local
        // replay id rides on replayTraceId, regardless of the SDK's field naming.
        // Any extra fields the SDK emits (e.g. sourceSpanId) are ignored by the
        // plugin. The deprecated sourceTraceId input key still feeds it.
        expect(event.item).toEqual({
            originalTraceId: "source-1",
            replayTraceId: "local-replay-1",
            error: null,
            durationMs: 5,
            itemPath: expect.stringContaining("source-1.json"),
        });
        expect(JSON.parse(readFileSync(event.item.itemPath, "utf8"))).toEqual({
            testRunId: "run-1",
            originalTraceId: "source-1",
            sourceTraceId: "source-1",
            traceId: null,
            replayTraceId: "local-replay-1",
            input: ["hi"],
            result: { ok: true },
            originalOutput: { ok: false },
            error: null,
            durationMs: 5,
        });
    });
    it("falls back to the legacy traceId remap when sourceTraceId is present but null", async () => {
        const childPath = join(tmpDir, "null-source-child.mjs");
        writeFileSync(childPath, [
            `const p = { completed: 1, total: 1, succeeded: 1, errored: 0, testRunId: "run-null", item: { traceId: "orig-1", sourceTraceId: null, replayTraceId: "local-1", error: null, durationMs: 3 } }`,
            `process.stderr.write("@@bitfab:progress " + JSON.stringify(p) + "\\n")`,
            `process.stdout.write(JSON.stringify({ testRunId: "run-null", items: [] }) + "\\n")`,
            `process.exit(0)`,
        ].join("\n"));
        const { eventsLogPath, exitCode } = await run([
            "--",
            process.execPath,
            childPath,
        ]);
        expect(exitCode).toBe(0);
        const [event] = readFileSync(eventsLogPath, "utf8")
            .trim()
            .split("\n")
            .map((line) => JSON.parse(line));
        expect(event.type).toBe("progress");
        // A present-but-null sourceTraceId is NOT the modern lineage shape: the
        // legacy remap treats traceId as the original trace, so the normalized
        // original id carries the known original instead of null.
        expect(event.item).toMatchObject({
            originalTraceId: "orig-1",
            replayTraceId: "local-1",
            error: null,
            durationMs: 3,
        });
    });
    it("does not duplicate progress item refs in the complete event for mixed payload runs", async () => {
        const childPath = join(tmpDir, "mixed-payload-child.mjs");
        writeFileSync(childPath, [
            `const p1 = { completed: 1, total: 2, succeeded: 1, errored: 0, testRunId: "mixed", item: { traceId: "source-1", replayTraceId: "local-replay-1", error: null, durationMs: 5, input: ["one"], result: { ok: true }, originalOutput: { ok: false } } }`,
            `process.stderr.write("@@bitfab:progress " + JSON.stringify(p1) + "\\n")`,
            `const p2 = { completed: 2, total: 2, succeeded: 1, errored: 1, testRunId: "mixed", item: { traceId: "source-2", replayTraceId: "local-replay-2", error: "boom", durationMs: 7 } }`,
            `process.stderr.write("@@bitfab:progress " + JSON.stringify(p2) + "\\n")`,
            `process.stdout.write(JSON.stringify({ testRunId: "mixed", items: [{ traceId: "server-1", input: ["one"], result: { ok: true }, originalOutput: { ok: false }, error: null, durationMs: 5 }, { traceId: "server-2", error: "boom", durationMs: 7 }] }) + "\\n")`,
            `process.exit(0)`,
        ].join("\n"));
        const { eventsLogPath, exitCode } = await run([
            "--",
            process.execPath,
            childPath,
        ]);
        expect(exitCode).toBe(0);
        const events = readFileSync(eventsLogPath, "utf8")
            .trim()
            .split("\n")
            .map((line) => JSON.parse(line));
        const [firstProgress, secondProgress, complete] = events;
        expect(firstProgress.item).toMatchObject({
            originalTraceId: "source-1",
            replayTraceId: "local-replay-1",
            itemPath: expect.stringContaining("source-1.json"),
        });
        expect(secondProgress.item).toEqual({
            originalTraceId: "source-2",
            replayTraceId: "local-replay-2",
            error: "boom",
            durationMs: 7,
        });
        expect(complete).toMatchObject({
            type: "complete",
            result: { testRunId: "mixed", itemCount: 2 },
        });
        expect(complete.items).toHaveLength(2);
        // These complete items carry no originalTraceId (an older SDK), so
        // item.traceId is the SERVER replay trace id and becomes the legacy
        // persist key.
        expect(complete.items.map((item) => item.traceId)).toEqual(["server-1", "server-2"]);
        expect(new Set(complete.items.map((item) => item.traceId))
            .size).toBe(2);
        expect(complete.items.some((item) => item.itemPath === firstProgress.item.itemPath)).toBe(false);
    });
    it("isolates run artifacts in a run directory and indexes them by test run id", async () => {
        const childPath = join(tmpDir, "run-dir-child.mjs");
        writeFileSync(childPath, [
            `const p = { completed: 1, total: 1, succeeded: 1, errored: 0, testRunId: "run-dir-test", item: { traceId: "source-1", replayTraceId: "local-1", error: null, durationMs: 5, result: { value: 42 } } }`,
            `process.stderr.write("@@bitfab:progress " + JSON.stringify(p) + "\\n")`,
            `process.stdout.write(JSON.stringify({ testRunId: "run-dir-test", items: [] }) + "\\n")`,
            `process.exit(0)`,
        ].join("\n"));
        const runDir = join(tmpDir, "isolated-run");
        const { exitCode } = await run([
            "--run-dir",
            runDir,
            "--",
            process.execPath,
            childPath,
        ]);
        expect(exitCode).toBe(0);
        const runMeta = JSON.parse(readFileSync(join(runDir, "run.json"), "utf8"));
        expect(runMeta).toMatchObject({
            status: "complete",
            testRunId: "run-dir-test",
            eventsLogPath: join(runDir, "events.jsonl"),
            itemsDir: join(runDir, "items"),
            logPath: join(runDir, "progress.log"),
            resultPath: join(runDir, "result.json"),
        });
        // The result JSON is a run artifact colocated with the rest, not a separate
        // scripts/replay-result.json path.
        const runResult = JSON.parse(readFileSync(join(runDir, "result.json"), "utf8"));
        expect(runResult.testRunId).toBe("run-dir-test");
        const testRunPointer = JSON.parse(readFileSync(join(tmpDir, "by-test-run", "run-dir-test", "run.json"), "utf8"));
        expect(testRunPointer.runDir).toBe(runDir);
        expect(testRunPointer.resultPath).toBe(join(runDir, "result.json"));
        const [event] = readFileSync(join(runDir, "events.jsonl"), "utf8")
            .trim()
            .split("\n")
            .map((line) => JSON.parse(line));
        expect(event.item.itemPath).toBe(join(runDir, "items", "source-1.json"));
    });
    it("writes one item file per replay item across progress and complete (no duplicate)", async () => {
        // A modern lineage item settles during progress (enriched) AND appears in the
        // final ReplayResult. Both writes must land on the same file (keyed by the
        // source/lineage trace id), so the item is not persisted twice under two names.
        const childPath = join(tmpDir, "one-file-child.mjs");
        writeFileSync(childPath, [
            `const p = { completed: 1, total: 1, succeeded: 1, errored: 0, testRunId: "one-file", item: { traceId: null, sourceTraceId: "src-1", error: null, durationMs: 5, input: ["hi"], result: { ok: true }, originalOutput: { ok: false } } }`,
            `process.stderr.write("@@bitfab:progress " + JSON.stringify(p) + "\\n")`,
            `process.stdout.write(JSON.stringify({ testRunId: "one-file", items: [{ traceId: null, sourceTraceId: "src-1", input: ["hi"], result: { ok: true }, originalOutput: { ok: false }, error: null, durationMs: 5 }] }) + "\\n")`,
            `process.exit(0)`,
        ].join("\n"));
        const runDir = join(tmpDir, "one-file-run");
        const { exitCode } = await run([
            "--run-dir",
            runDir,
            "--",
            process.execPath,
            childPath,
        ]);
        expect(exitCode).toBe(0);
        // Exactly one item file, keyed by the source (lineage) trace id, so the
        // live progress write and the final complete write land on the same file.
        expect(readdirSync(join(runDir, "items"))).toEqual(["src-1.json"]);
        const [progress, complete] = readFileSync(join(runDir, "events.jsonl"), "utf8")
            .trim()
            .split("\n")
            .map((line) => JSON.parse(line));
        // Progress and complete reference the SAME file.
        expect(progress.item.itemPath).toBe(join(runDir, "items", "src-1.json"));
        expect(complete.items[0].itemPath).toBe(progress.item.itemPath);
        // The final file carries the lineage keys the persist step reads. The local
        // replay id is never surfaced, so replayTraceId is null.
        expect(JSON.parse(readFileSync(complete.items[0].itemPath, "utf8"))).toMatchObject({
            testRunId: "one-file",
            sourceTraceId: "src-1",
            replayTraceId: null,
            traceId: null,
        });
    });
    it("adds replay artifacts to local git exclude without changing tracked gitignore", async () => {
        mkdirSync(join(tmpDir, ".git", "info"), { recursive: true });
        writeFileSync(join(tmpDir, ".gitignore"), "node_modules/\n");
        const childPath = writeNoProgressChild(0);
        const { exitCode } = await run([
            "--run-dir",
            join(tmpDir, "git-excluded-run"),
            "--",
            process.execPath,
            childPath,
        ]);
        expect(exitCode).toBe(0);
        expect(readFileSync(join(tmpDir, ".gitignore"), "utf8")).toBe("node_modules/\n");
        const exclude = readFileSync(join(tmpDir, ".git", "info", "exclude"), "utf8");
        // Every run's artifacts live under .bitfab/replays/; the legacy fixed result
        // path stays excluded for pre-run-dir scripts that self-write it.
        expect(exclude).toContain(".bitfab/replays/");
        expect(exclude).toContain("scripts/replay-result.json");
    });
    it("propagates the child's non-zero exit code and prints a failed close line", async () => {
        const childPath = writeFakeChild(2, 7);
        const outPath = join(tmpDir, "r2.json");
        const { exitCode, stdout } = await run([
            "--out",
            outPath,
            "--",
            process.execPath,
            childPath,
        ]);
        expect(exitCode).toBe(7);
        expect(stdout).toContain("✓ 1/2 · 1.0s");
        expect(stdout).toContain(`✗ failed (exit 7) · replay command exited non-zero · check ${outPath}`);
        expect(stdout).not.toMatch(/✓ done · 2 ok/);
    });
    it("preserves a script-written result file when captured stdout is not JSON", async () => {
        // The Bugbot case: a script that prints human text to stdout (not JSON) but
        // wrote the real ReplayResult JSON to --out itself. The wrapper must NOT
        // clobber that good file with the human stdout.
        const outPath = join(tmpDir, "script-written-result.json");
        const childPath = join(tmpDir, "nonjson-child.mjs");
        writeFileSync(childPath, [
            `import { writeFileSync } from "node:fs"`,
            `const p = { completed: 1, total: 1, succeeded: 1, errored: 0, item: { traceId: "t1", error: null, durationMs: 5 } }`,
            `process.stderr.write("@@bitfab:progress " + JSON.stringify(p) + "\\n")`,
            `writeFileSync(${JSON.stringify(outPath)}, JSON.stringify({ testRunId: "from-script", items: [] }))`,
            `process.stdout.write("Replayed 1 trace, all good\\n")`,
            `process.exit(0)`,
        ].join("\n"));
        const { exitCode, stderr } = await run([
            "--total",
            "1",
            "--out",
            outPath,
            "--",
            process.execPath,
            childPath,
        ]);
        expect(exitCode).toBe(0);
        // The script-written JSON survives; the human stdout did NOT overwrite it.
        expect(JSON.parse(readFileSync(outPath, "utf8")).testRunId).toBe("from-script");
        // A result file is authoritative, so noisy stdout does not matter.
        expect(stderr).not.toContain("captured stdout is not valid JSON");
    });
    it("passes BITFAB_REPLAY_RESULT_PATH and treats that file as authoritative", async () => {
        const outPath = join(tmpDir, "env-result.json");
        const childPath = join(tmpDir, "env-result-child.mjs");
        writeFileSync(childPath, [
            `import { writeFileSync } from "node:fs"`,
            `const p = { completed: 1, total: 1, succeeded: 1, errored: 0, item: { traceId: "t1", error: null, durationMs: 5 } }`,
            `process.stderr.write("@@bitfab:progress " + JSON.stringify(p) + "\\n")`,
            `writeFileSync(process.env.BITFAB_REPLAY_RESULT_PATH, JSON.stringify({ testRunId: "from-file", items: [{ traceId: "server-file" }] }))`,
            `process.stdout.write(JSON.stringify({ testRunId: "from-stdout", items: [{ traceId: "server-stdout" }] }) + "\\n")`,
            `process.exit(0)`,
        ].join("\n"));
        const { exitCode, eventsLogPath } = await run([
            "--out",
            outPath,
            "--",
            process.execPath,
            childPath,
        ]);
        expect(exitCode).toBe(0);
        expect(JSON.parse(readFileSync(outPath, "utf8")).testRunId).toBe("from-file");
        const events = readFileSync(eventsLogPath, "utf8")
            .trim()
            .split("\n")
            .map((line) => JSON.parse(line));
        expect(events.at(-1)).toMatchObject({
            type: "complete",
            result: { testRunId: "from-file", itemCount: 1 },
            items: [{ traceId: "server-file" }],
        });
    });
    it("builds the complete row and item files from a streamed terminal event despite noisy stdout", async () => {
        // Fix C: a modern SDK streams the enriched ReplayResult as a terminal
        // `complete` sentinel on stderr, so a dependency flooding stdout with
        // non-JSON (BAML / llmTracking) can no longer block the final result.
        const childPath = writeStreamedCompleteChild();
        const runDir = join(tmpDir, `run-streamed-${runSeq}`);
        const { exitCode, stderr } = await run([
            "--label",
            "fixc",
            "--run-dir",
            runDir,
            "--",
            process.execPath,
            childPath,
        ]);
        expect(exitCode).toBe(0);
        // The sentinel delivered the result, so no stdout-parse warning fired even
        // though stdout was pure noise.
        expect(stderr).not.toContain("captured stdout is not valid JSON");
        // events.jsonl carries a complete row built from the streamed result.
        const events = readFileSync(join(runDir, "events.jsonl"), "utf8")
            .trim()
            .split("\n")
            .map((line) => JSON.parse(line));
        const complete = events.find((e) => e.type === "complete");
        expect(complete).toBeDefined();
        expect(complete?.result?.testRunId).toBe("run-c");
        expect(complete?.items?.length).toBe(2);
        // One item file per replay item, keyed by the source (lineage) trace id, 1:1.
        const itemFiles = readdirSync(join(runDir, "items")).sort();
        expect(itemFiles).toEqual(["src-1.json", "src-2.json"]);
        const item = JSON.parse(readFileSync(join(runDir, "items", "src-1.json"), "utf8"));
        expect(item).toMatchObject({
            sourceTraceId: "src-1",
            replayTraceId: null,
            traceId: null,
        });
    });
    it("does not treat a stale preexisting result file as this run's result", async () => {
        const outPath = join(tmpDir, "stale-result.json");
        writeFileSync(outPath, JSON.stringify({ testRunId: "stale", items: [] }));
        const childPath = join(tmpDir, "stale-result-child.mjs");
        writeFileSync(childPath, [
            `const p = { completed: 1, total: 1, succeeded: 1, errored: 0, item: { traceId: "t1", error: null, durationMs: 5 } }`,
            `process.stderr.write("@@bitfab:progress " + JSON.stringify(p) + "\\n")`,
            `process.stdout.write("human output only\\n")`,
            `process.exit(0)`,
        ].join("\n"));
        const { exitCode, stdout, stderr } = await run([
            "--out",
            outPath,
            "--",
            process.execPath,
            childPath,
        ]);
        expect(exitCode).toBe(1);
        expect(stdout).toContain(`✗ failed · replay finished without ReplayResult JSON · check ${outPath}`);
        expect(stderr).toContain("captured stdout is not valid JSON");
    });
    it("fails a successful child when progress arrived but no result JSON exists", async () => {
        const childPath = join(tmpDir, "missing-result-child.mjs");
        writeFileSync(childPath, [
            `const p = { completed: 1, total: 1, succeeded: 1, errored: 0, item: { traceId: "t1", error: null, durationMs: 5 } }`,
            `process.stderr.write("@@bitfab:progress " + JSON.stringify(p) + "\\n")`,
            `process.exit(0)`,
        ].join("\n"));
        const outPath = join(tmpDir, "missing-result.json");
        const { exitCode, stdout } = await run([
            "--out",
            outPath,
            "--",
            process.execPath,
            childPath,
        ]);
        expect(exitCode).toBe(1);
        expect(stdout).toContain("✓ 1/1 · 0.0s");
        expect(stdout).toContain(`✗ failed · replay finished without ReplayResult JSON · check ${outPath}`);
        expect(stdout).not.toMatch(/✓ done · 1 ok/);
    });
    it("emits a liveness heartbeat during a quiet stretch between traces", async () => {
        // Child settles trace 1, then goes quiet for 400ms (a slow trace) before
        // finishing, so with a short heartbeat interval at least one heartbeat fires.
        const childPath = join(tmpDir, "slow-child.mjs");
        writeFileSync(childPath, [
            `const sleep = (ms) => new Promise((r) => setTimeout(r, ms))`,
            `const p1 = { completed: 1, total: 2, succeeded: 1, errored: 0, item: { traceId: "t1", error: null, durationMs: 50 } }`,
            `process.stderr.write("@@bitfab:progress " + JSON.stringify(p1) + "\\n")`,
            `await sleep(400)`,
            `const p2 = { completed: 2, total: 2, succeeded: 2, errored: 0, item: { traceId: "t2", error: null, durationMs: 50 } }`,
            `process.stderr.write("@@bitfab:progress " + JSON.stringify(p2) + "\\n")`,
            `process.stdout.write(JSON.stringify({ testRunId: "hb", items: [] }) + "\\n")`,
            `process.exit(0)`,
        ].join("\n"));
        const { stdout, exitCode } = await run(["--label", "slow", "--total", "2", "--", process.execPath, childPath], { BITFAB_REPLAY_HEARTBEAT_MS: "80" });
        expect(exitCode).toBe(0);
        // A heartbeat names the running count and elapsed, and the run still finishes.
        expect(stdout).toMatch(/… 1\/2 running · \d+s elapsed/);
        expect(stdout).toContain("✓ 2/2 · 0.1s");
    });
    it("guards a ran-but-silent replay (no events, exit 0) with an upgrade hint", async () => {
        const childPath = writeNoProgressChild(0);
        const { stdout, exitCode, eventsLogPath } = await run([
            "--label",
            "generate-email",
            "--total",
            "8",
            "--",
            process.execPath,
            childPath,
        ]);
        expect(exitCode).toBe(0);
        // Header still prints; the close guard explains the missing per-trace lines
        // instead of ending in silence, and points at the upgrade / onProgress wiring.
        expect(stdout).toContain("▶ generate-email · 8 traces");
        expect(stdout).toContain("⚠ done · replay finished but reported no progress · its @bitfab/sdk predates progress reporting, or onProgress isn't wired");
        const events = readFileSync(eventsLogPath, "utf8")
            .trim()
            .split("\n")
            .map((line) => JSON.parse(line));
        expect(events).toEqual([
            {
                type: "complete",
                result: { testRunId: "np", itemCount: 0 },
                items: [],
            },
        ]);
        // It is NOT a success summary (no "ok"/"failed" counts), and never a hang.
        expect(stdout).not.toMatch(/✓ done|⚠ done · \d+ ok/);
    });
    it("forwards the replay's own stderr instead of swallowing it (no worse than bare)", async () => {
        // A replay that prints a progress line AND a plain error line to stderr.
        const childPath = join(tmpDir, "stderr-child.mjs");
        writeFileSync(childPath, [
            `const p = { completed: 1, total: 1, succeeded: 0, errored: 1, item: { traceId: "t1", error: "boom", durationMs: 10 } }`,
            `process.stderr.write("@@bitfab:progress " + JSON.stringify(p) + "\\n")`,
            `process.stderr.write("ReplayError: could not reach the server\\n")`,
            `process.stdout.write(JSON.stringify({ testRunId: "se", items: [] }) + "\\n")`,
            `process.exit(0)`,
        ].join("\n"));
        const { stdout, stderr, exitCode } = await run([
            "--total",
            "1",
            "--",
            process.execPath,
            childPath,
        ]);
        expect(exitCode).toBe(0);
        // The replay's non-sentinel stderr survives on OUR stderr...
        expect(stderr).toContain("ReplayError: could not reach the server");
        // ...the sentinel line is consumed (not echoed raw to either stream)...
        expect(stderr).not.toContain("@@bitfab:progress");
        expect(stdout).not.toContain("@@bitfab:progress");
        // ...and the formatted per-trace line still lands on stdout.
        expect(stdout).toContain("✗ 1/1 · 0.0s · boom");
    });
    it("guards a failed replay that reported nothing with the exit code and result path", async () => {
        const childPath = writeNoProgressChild(2);
        const outPath = join(tmpDir, "fail-result.json");
        const { stdout, exitCode } = await run([
            "--out",
            outPath,
            "--",
            process.execPath,
            childPath,
        ]);
        expect(exitCode).toBe(2);
        expect(stdout).toContain(`✗ failed (exit 2) · no progress reported · check ${outPath}`);
    });
    it("exits 1 with usage when no command is given", async () => {
        const { exitCode, stdout } = await run([]);
        // usage goes to stderr (inherited); just assert the exit code + no progress
        expect(exitCode).toBe(1);
        expect(stdout).not.toContain("▶ ");
    });
    // When --out is omitted the result JSON is a run artifact at
    // <run-dir>/result.json, colocated with the rest, never a separate fixed path.
    // A stdout-only script (predating the SDK file contract) still resolves: the
    // wrapper writes its captured JSON into the run dir.
    it("writes the result into the run dir when --out is omitted", async () => {
        const childPath = writeNoProgressChild(0);
        const runDir = join(tmpDir, "omitted-out-run");
        const { exitCode } = await run([
            "--run-dir",
            runDir,
            "--",
            process.execPath,
            childPath,
        ]);
        expect(exitCode).toBe(0);
        const result = JSON.parse(readFileSync(join(runDir, "result.json"), "utf8"));
        expect(result.testRunId).toBe("np");
    });
    it("resolves via the legacy scripts/replay-result.json a pre-run-dir script self-writes (no --out)", async () => {
        // Pre-run-dir pattern: the script writes the old fixed result file and prints
        // a human summary (not JSON) to stdout. The wrapper never writes that path
        // anymore, but still reads it as a fallback so the script resolves instead of
        // failing on unparseable stdout. Run in an isolated cwd so the self-written
        // scripts/replay-result.json cannot leak into other tests sharing tmpDir.
        const isolatedCwd = mkdtempSync(join(tmpdir(), "replay-legacy-"));
        const childPath = join(isolatedCwd, "legacy-filewriter.mjs");
        writeFileSync(childPath, [
            `import { mkdirSync, writeFileSync } from "node:fs"`,
            `mkdirSync("scripts", { recursive: true })`,
            `writeFileSync("scripts/replay-result.json", JSON.stringify({ testRunId: "legacy", items: [] }))`,
            `process.stdout.write("Replayed 3 · ok 3 · errored 0\\n")`,
            `process.exit(0)`,
        ].join("\n"));
        const { exitCode } = await run(["--", process.execPath, childPath], {}, isolatedCwd);
        expect(exitCode).toBe(0);
        rmSync(isolatedCwd, { recursive: true, force: true });
    });
    it("ignores a stale legacy scripts/replay-result.json in favor of valid current-run stdout", async () => {
        // A leftover scripts/replay-result.json from an earlier run must not beat
        // this run's fresh stdout JSON. The wrapper clears the legacy path before
        // spawning, so the legacy fallback only ever returns a file this run wrote.
        // Isolated cwd so the pre-seeded legacy file cannot leak into other tests.
        const isolatedCwd = mkdtempSync(join(tmpdir(), "replay-stale-legacy-"));
        mkdirSync(join(isolatedCwd, "scripts"), { recursive: true });
        writeFileSync(join(isolatedCwd, "scripts", "replay-result.json"), JSON.stringify({ testRunId: "stale-legacy", items: [] }));
        const childPath = join(isolatedCwd, "fresh-stdout-child.mjs");
        writeFileSync(childPath, [
            `const p = { completed: 1, total: 1, succeeded: 1, errored: 0, testRunId: "fresh-run", item: { traceId: "t1", error: null, durationMs: 5 } }`,
            `process.stderr.write("@@bitfab:progress " + JSON.stringify(p) + "\\n")`,
            `process.stdout.write(JSON.stringify({ testRunId: "fresh-run", items: [] }) + "\\n")`,
            `process.exit(0)`,
        ].join("\n"));
        const runDir = join(isolatedCwd, "fresh-run-dir");
        const { exitCode } = await run(["--run-dir", runDir, "--", process.execPath, childPath], {}, isolatedCwd);
        expect(exitCode).toBe(0);
        const result = JSON.parse(readFileSync(join(runDir, "result.json"), "utf8"));
        expect(result.testRunId).toBe("fresh-run");
        rmSync(isolatedCwd, { recursive: true, force: true });
    });
    it("copies a legacy-fallback result into the run dir so resultPath is never missing", async () => {
        // When only the legacy scripts/replay-result.json resolves the run, the
        // wrapper must still populate the canonical <run-dir>/result.json that
        // run.json advertises, so consumers never see a missing artifact.
        const isolatedCwd = mkdtempSync(join(tmpdir(), "replay-legacy-canonical-"));
        const childPath = join(isolatedCwd, "legacy-canonical-child.mjs");
        writeFileSync(childPath, [
            `import { mkdirSync, writeFileSync } from "node:fs"`,
            `const p = { completed: 1, total: 1, succeeded: 1, errored: 0, item: { traceId: "t1", error: null, durationMs: 5 } }`,
            `process.stderr.write("@@bitfab:progress " + JSON.stringify(p) + "\\n")`,
            `mkdirSync("scripts", { recursive: true })`,
            `writeFileSync("scripts/replay-result.json", JSON.stringify({ testRunId: "legacy-canonical", items: [] }))`,
            `process.stdout.write("Replayed 1 · ok 1 · errored 0\\n")`,
            `process.exit(0)`,
        ].join("\n"));
        const runDir = join(isolatedCwd, "legacy-canonical-run");
        const { exitCode } = await run(["--run-dir", runDir, "--", process.execPath, childPath], {}, isolatedCwd);
        expect(exitCode).toBe(0);
        const result = JSON.parse(readFileSync(join(runDir, "result.json"), "utf8"));
        expect(result.testRunId).toBe("legacy-canonical");
        rmSync(isolatedCwd, { recursive: true, force: true });
    });
});
